/* adm-master-interface-sql-oracle.xml - selectInterfaceLogCount */
SELECT COUNT(1)
  FROM INTERFACE_LOG


		AND #{SEARCH_CONDITION}

/* adm-master-interface-sql-oracle.xml - selectInterfaceLogList */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT B.* FROM ( SELECT IFID , IFNM , REQDT , IFTYPE , STATUS , ISPROCESS , BATEXECID , TO_CHAR(INSERTDATE, 'YYYYMMDDHH24MISS') AS INSERTDATE , TO_CHAR(UPDATEDATE, 'YYYYMMDDHH24MISS') AS UPDATEDATE FROM INTERFACE_LOG
AND #{SEARCH_CONDITION}
ORDER BY IFID DESC ) B #{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* adm-master-interface-sql-oracle.xml - selectInterfaceLog */
SELECT
      REQDATA
	, COALESCE(RESDATA, ERRMSG) AS RESDATA
FROM INTERFACE_LOG

	AND IFID = #{ifid}
